.instruction-text {
    color: #e2e8f0;
    font-size: 1.1rem;
    font-weight: 500;
    height: 30px; /* Fixed height so buttons don't jump around */
    margin-bottom: 30px;
}

/* --- Action Buttons --- */
.enrollment-actions {
    display: flex;
    justify-content: center;
    gap: 15px;
}

.capture-btn {
    background: #3b82f6;
    color: white;
    border: none;
    padding: 14px 40px;
    border-radius: 12px;
    font-size: 1.1rem;
    font-weight: 700;
    cursor: pointer;
    box-shadow: 0 4px 15px rgba(59, 130, 246, 0.4);
    transition: all 0.2s;
    width: 100%;
    max-width: 300px;
}

.capture-btn:hover {
    background: #2563eb;
    transform: translateY(-2px);
}

.capture-btn:active {
    transform: translateY(1px);
}

.retake-btn {
    background: transparent;
    color: #94a3b8;
    border: 1px solid #475569;
    padding: 14px 30px;
    border-radius: 12px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
}

.retake-btn:hover {
    background: #334155;
    color: #f8fafc;
}

.submit-btn {
    background: #10b981;
    color: white;
    border: none;
    padding: 14px 40px;
    border-radius: 12px;
    font-size: 1.1rem;
    font-weight: 700;
    cursor: pointer;
    box-shadow: 0 4px 15px rgba(16, 185, 129, 0.4);
    transition: all 0.2s;
    flex-grow: 1;
    max-width: 300px;
}

.submit-btn:hover:not(:disabled) {
    background: #059669;
    transform: translateY(-2px);
}

.submit-btn:disabled {
    background: #475569;
    color: #94a3b8;
    cursor: not-allowed;
    box-shadow: none;
}

/* --- Animations --- */
@keyframes slideUpFade {
    from { transform: translateY(30px); opacity: 0; }
    to { transform: translateY(0); opacity: 1; }
}

@keyframes fadeIn {
    from { opacity: 0; transform: scale(0.9); }
    to { opacity: 1; transform: scale(1); }
}

