.chat-popup-wrapper {
  position: fixed;
  bottom: 90px;
  right: 7px;
  z-index: 1000;
  font-family: 'Inter', sans-serif;
}

/* Floating Action Button */
.chat-fab {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background: linear-gradient(135deg, #60a5fa, #34d399); /* FlowGuard Gradient */
  border: none;
  color: white;
  font-size: 1.5rem;
  cursor: pointer;
  box-shadow: 0 4px 15px rgba(59, 130, 246, 0.4);
  transition: transform 0.3s ease;
}

.chat-fab:hover {
  transform: scale(1.1);
}

/* Chat Window Container */
.chat-window {
  position: absolute;
  bottom: 80px;
  right: 0;
  width: 350px;
  height: 450px;
  background-color: #1e293b;
  border: 1px solid #334155;
  border-radius: 16px;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.5);
  animation: slideUp 0.3s ease-out;
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Header */
.chat-header {
  padding: 15px 20px;
  background-color: #0f172a;
  border-bottom: 1px solid #334155;
  display: flex;
  align-items: center;
  gap: 10px;
}

.chat-header h3 {
  margin: 0;
  font-size: 1rem;
  color: #f8fafc;
}

.ai-status-dot {
  width: 8px;
  height: 8px;
  background-color: #10b981;
  border-radius: 50%;
  box-shadow: 0 0 8px #10b981;
}

/* Messages Area */
.chat-messages {
  flex: 1;
  padding: 20px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.message-bubble {
  max-width: 80%;
  padding: 10px 14px;
  border-radius: 12px;
  font-size: 0.9rem;
  line-height: 1.4;
}

.ai-bubble {
  align-self: flex-start;
  background-color: #334155;
  color: #f8fafc;
  border-bottom-left-radius: 2px;
}

.user-bubble {
  align-self: flex-end;
  background-color: #3b82f6;
  color: white;
  border-bottom-right-radius: 2px;
}

/* Input Area */
.chat-input-area {
  padding: 15px;
  background-color: #0f172a;
  display: flex;
  gap: 10px;
}

.chat-input-area input {
  flex: 1;
  background-color: #1e293b;
  border: 1px solid #334155;
  color: white;
  padding: 8px 12px;
  border-radius: 6px;
  outline: none;
}

.chat-input-area button {
  background-color: #3b82f6;
  color: white;
  border: none;
  padding: 8px 15px;
  border-radius: 6px;
  font-weight: 600;
  cursor: pointer;
}

/* Mobile Adjustments */
@media (max-width: 480px) {
  .chat-window {
    width: calc(100vw - 40px);
    right: -10px;
  }
}

