1	import React, { useRef, useState, useEffect } from 'react';
2	import axios from 'axios';
3	import Sidebar from '../components/Sidebar';
4	import '../css/Dashboard.css';
5	import '../css/VPatrol.css'; 
6	
7	const VPatrol = () => {
8	  const videoRef = useRef(null);
9	  const canvasRef = useRef(null);
10	  
11	  // Staged States: SYSTEM_ACTIVE, PRESENCE_DETECTED, TARGET_LOCKING, LIVENESS_CHECK, SECURE_MATCH, UNKNOWN_QUERY
12	  const [scanStatus, setScanStatus] = useState("SYSTEM_ACTIVE"); 
13	  const [identifiedUser, setIdentifiedUser] = useState(null);
14	  const [faceBox, setFaceBox] = useState(null); 
15	  const [scanProgress, setScanProgress] = useState(0); 
16	  
17	  const scanStatusRef = useRef("SYSTEM_ACTIVE");
18	  const lockTimerRef = useRef(null);
19	  const progressIntervalRef = useRef(null);
20	
21	  const isScanningRef = useRef(false);
22	
23	  // LIVENESS MEMORY: Tracks the head-turn validation
24	  const candidateUserRef = useRef(null); 
25	  const lastLogRef = useRef({ name: null, timestamp: 0 });
26	
27	  const [systemTime, setSystemTime] = useState(new Date().toLocaleTimeString('en-SG', { 
28	    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true 
29	  }));
30	
31	  const [incidentLogs, setIncidentLogs] = useState([]);
32	
33	  const token = localStorage.getItem("accessToken");
34	  const NODE_SERVER_URL = "http://localhost:5000/api/security/logs"; 
35	
36	  const changeScanState = (nextState) => {
37	    setScanStatus(nextState);
38	    scanStatusRef.current = nextState;
39	  };
40	
41	  useEffect(() => {
42	    startCCTV();
43	
44	    // FETCH PERMANENT LOGS ON LOAD
45	    axios.get(NODE_SERVER_URL, { headers: { Authorization: `Bearer ${token}` } })
46	      .then(res => {
47	        if (res.data && res.data.length > 0) {
48	          setIncidentLogs(res.data);
49	        } else {
50	          setIncidentLogs([{ id: 'SYS-001', time: new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true }), type: 'System Online', desc: 'Biometric sensors initialized.', severity: 'safe', icon: '✅' }]);
51	        }
52	      })
53	      .catch(err => {
54	        console.error("Database connection waiting...", err);
55	        setIncidentLogs([{ id: 'SYS-001', time: new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true }), type: 'System Offline', desc: 'Cannot connect to security database.', severity: 'critical', icon: '⚠️' }]);
56	      });
57	
58	    const clockInterval = setInterval(() => {
59	      setSystemTime(new Date().toLocaleTimeString('en-SG', { 
60	        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true 
61	      }));
62	    }, 1000);
63	
64	    const scanInterval = setInterval(() => { 
65	      performLiveScan(); 
66	    }, 800); 
67	
68	    return () => {
69	      stopCCTV();
70	      clearInterval(clockInterval);
71	      clearInterval(scanInterval);
72	      if (lockTimerRef.current) clearTimeout(lockTimerRef.current);
73	      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
74	    };
75	  }, []);
76	
77	  const startCCTV = async () => {
78	    try {
79	      const stream = await navigator.mediaDevices.getUserMedia({ 
80	        video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: "user" } 
81	      });
82	      if (videoRef.current) videoRef.current.srcObject = stream;
83	      changeScanState("SYSTEM_ACTIVE");
84	    } catch (err) { 
85	      changeScanState("HARDWARE_ERR"); 
86	    }
87	  };
88	
89	  const stopCCTV = () => {
90	    if (videoRef.current?.srcObject) {
91	      videoRef.current.srcObject.getTracks().forEach(track => track.stop());
92	    }
93	  };
94	
95	  const playFeedback = (type) => {
96	    const audioPath = type === 'success' ? '/sounds/success.mp3' : '/sounds/denied.mp3';
97	    const audio = new Audio(audioPath);
98	    audio.volume = 0.4; 
99	    audio.play().catch(() => console.log("Audio waiting for user gesture"));
100	  };
101	
102	  const grantFinalAccess = (detectedName) => {
103	    playFeedback('success');
104	    changeScanState("SECURE_MATCH");
105	    setIdentifiedUser(detectedName);
106	    setScanProgress(100);
107	    
108	    const currentTimestamp = Date.now();
109	    const logTimeStr = new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
110	
111	    if (lastLogRef.current.name !== detectedName || (currentTimestamp - lastLogRef.current.timestamp > 30000)) {
112	      const newLog = {
113	        id: `ACC-${Math.floor(Math.random() * 900) + 100}`,
114	        time: logTimeStr,
115	        type: 'Gantry Access',
116	        desc: `Identity & Liveness Verified: ${detectedName}`,
117	        severity: 'safe',
118	        icon: '🔓',
119	        personnelName: detectedName 
120	      };
121	      
122	      setIncidentLogs(prev => [newLog, ...prev.slice(0, 14)]); 
123	      lastLogRef.current = { name: detectedName, timestamp: currentTimestamp };
124	      
125	      axios.post(NODE_SERVER_URL, newLog, { headers: { Authorization: `Bearer ${token}` } })
126	        .catch(e => console.log("DB Save Failed", e));
127	    }
128	
129	    setTimeout(() => { resetScanner(); }, 3500);
130	  };
131	
132	  const performLiveScan = async () => {
133	    if (isScanningRef.current) return; 
134	
135	    const video = videoRef.current;
136	    const canvas = canvasRef.current;
137	    
138	    if (!video || !canvas || video.videoWidth === 0) return;
139	    if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") return;
140	
141	    isScanningRef.current = true; 
142	
143	    const context = canvas.getContext('2d');
144	    
145	    // 🚀 LAPTOP OPTIMIZATION: Shrink the image to 480px wide before sending to AI
146	    // This dramatically reduces the mathematical load on your laptop's weak CPU!
147	    const MAX_WIDTH = 480; 
148	    const scaleDownRatio = MAX_WIDTH / video.videoWidth;
149	    
150	    canvas.width = MAX_WIDTH;
151	    canvas.height = video.videoHeight * scaleDownRatio;
152	    
153	    // Draw the compressed version
154	    context.drawImage(video, 0, 0, canvas.width, canvas.height);
155	    
156	    // Send a highly compressed JPEG
157	    const imageBase64 = canvas.toDataURL('image/jpeg', 0.3);
158	
159	    try {
160	      const res = await axios.post('/ai/user/recognize', 
161	        { image: imageBase64 }, 
162	        { headers: { Authorization: `Bearer ${token}` } }
163	      );
164	
165	      if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") {
166	         isScanningRef.current = false;
167	         return;
168	      }
169	
170	      if (res.data && res.data.box && res.data.box.length >= 4) {
171	        
172	        let rawX, rawY, boxWidth, boxHeight;
173	        const [v1, v2, v3, v4] = res.data.box;
174	
175	        // Note: The AI is now returning coordinates based on the SMALL 480px canvas, not the video
176	        if (v3 > v1 && v4 > v2 && v3 <= canvas.width && v4 <= canvas.height) {
177	          rawX = v1; rawY = v2; boxWidth = v3 - v1; boxHeight = v4 - v2;
178	        } else if (v2 > v4 && v3 > v1) {
179	          rawY = v1; rawX = v4; boxWidth = v2 - v4; boxHeight = v3 - v1; 
180	        } else {
181	          rawX = v1; rawY = v2; boxWidth = v3; boxHeight = v4;
182	        }
183	        
184	        // Calculate proximity based on the compressed canvas width
185	        const faceProximityPercentage = (boxWidth / canvas.width) * 100; 
186	        const livenessRatio = res.data.liveness_ratio || 0.5;
187	
188	        // 🎯 UPDATED MATH: Calculate percentages using the compressed canvas dimensions
189	        const targetBox = {
190	          left: `${(rawX / canvas.width) * 100}%`,
191	          top: `${(rawY / canvas.height) * 100}%`,
192	          width: `${(boxWidth / canvas.width) * 100}%`,
193	          height: `${(boxHeight / canvas.height) * 100}%`
194	        };
195	
196	        if (faceProximityPercentage < 5 && scanStatusRef.current !== "LIVENESS_CHECK") {
197	          if (scanStatusRef.current === "SYSTEM_ACTIVE" || scanStatusRef.current === "PRESENCE_DETECTED") {
198	            changeScanState("PRESENCE_DETECTED");
199	            setFaceBox(null); 
200	            setScanProgress(0);
201	          }
202	          isScanningRef.current = false; 
203	          return;
204	        }
205	
206	        if (scanStatusRef.current === "LIVENESS_CHECK") {
207	          setFaceBox(targetBox); 
208	          
209	          if (livenessRatio < 0.45 || livenessRatio > 0.55) {
210	            grantFinalAccess(candidateUserRef.current);
211	          }
212	          return; 
213	        }
214	
215	        if (scanStatusRef.current === "SYSTEM_ACTIVE" || scanStatusRef.current === "PRESENCE_DETECTED") {
216	          changeScanState("TARGET_LOCKING");
217	          setFaceBox(targetBox);
218	          setScanProgress(12);
219	
220	          let progress = 12;
221	          progressIntervalRef.current = setInterval(() => {
222	            progress += Math.floor(Math.random() * 14) + 4;
223	            if (progress >= 96) {
224	              setScanProgress(96);
225	              clearInterval(progressIntervalRef.current);
226	            } else {
227	              setScanProgress(progress);
228	            }
229	          }, 120);
230	
231	          lockTimerRef.current = setTimeout(() => {
232	            clearInterval(progressIntervalRef.current);
233	            
234	            const currentTimestamp = Date.now();
235	            const logTimeStr = new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
236	
237	            if (res.data.user && res.data.user.name !== "UNAUTHORIZED") {
238	              candidateUserRef.current = res.data.user.name;
239	              changeScanState("LIVENESS_CHECK");
240	            } else {
241	              playFeedback('denied');
242	              changeScanState("UNKNOWN_QUERY");
243	              setIdentifiedUser("UNKNOWN PERSONNEL");
244	              setScanProgress(0);
245	
246	              if (lastLogRef.current.name !== "UNKNOWN" || (currentTimestamp - lastLogRef.current.timestamp > 10000)) {
247	                const newLog = {
248	                  id: `SEC-${Math.floor(Math.random() * 900) + 100}`,
249	                  time: logTimeStr,
250	                  type: 'Intrusion Alert',
251	                  desc: 'Unregistered personnel detected at gantry.',
252	                  severity: 'critical',
253	                  icon: '🚨',
254	                  personnelName: null
255	                };
256	
257	                setIncidentLogs(prev => [newLog, ...prev.slice(0, 14)]);
258	                lastLogRef.current = { name: "UNKNOWN", timestamp: currentTimestamp };
259	                
260	                axios.post(NODE_SERVER_URL, newLog, { headers: { Authorization: `Bearer ${token}` } })
261	                  .catch(e => console.log("DB Save Failed", e));
262	              }
263	
264	              setTimeout(() => { resetScanner(); }, 3500);
265	            }
266	          }, 1800);
267	
268	        } else if (scanStatusRef.current === "TARGET_LOCKING") {
269	          setFaceBox(targetBox);
270	        }
271	
272	      } else {
273	        if (scanStatusRef.current !== "LIVENESS_CHECK" && scanStatusRef.current !== "TARGET_LOCKING") {
274	          resetScanner();
275	        }
276	      }
277	    } catch (err) {
278	      console.error("AI Command Loop Fault:", err);
279	    } finally {
280	      isScanningRef.current = false; 
281	    }
282	  };
283	
284	  const resetScanner = () => {
285	    setIdentifiedUser(null);
286	    setFaceBox(null);
287	    setScanProgress(0);
288	    candidateUserRef.current = null;
289	    changeScanState("SYSTEM_ACTIVE");
290	  };
291	
292	  return (
293	    <div className="dashboard-layout">
294	      <Sidebar />
295	      <main className="dashboard-main">
296	        <header className="dashboard-header">
297	          <div className="header-titles">
298	            <h1>V-Patrol AI Command Center</h1>
299	            <p>Real-time biometric gantry and anomaly detection timeline</p>
300	          </div>
301	        </header>
302	
303	        <div className="vpatrol-grid">
304	          <div className="vpatrol-card monitor-section">
305	            <div className={`cctv-container state-theme-${scanStatus.toLowerCase()}`}>
306	              <video ref={videoRef} autoPlay playsInline muted className="video-feed" />
307	              <canvas ref={canvasRef} style={{ display: 'none' }} />
308	              
309	              {faceBox && (
310	                <div 
311	                  className={`face-tracking-box state-${scanStatus.toLowerCase()}`}
312	                  style={{
313	                    top: faceBox.top,
314	                    left: faceBox.left,
315	                    width: faceBox.width,
316	                    height: faceBox.height
317	                  }}
318	                >
319	                  <div className="corner-bracket top-left"></div>
