1	/* =========================================
2	   1. V-PATROL LAYOUT CONFIGURATION
3	   ========================================= */
4	.vpatrol-grid {
5	    display: grid;
6	    grid-template-columns: 1.5fr 1fr;
7	    gap: 12px;
8	}
9	
10	.vpatrol-card {
11	    background: #1e2539;
12	    border-radius: 16px;
13	    border: 1px solid #2d364f;
14	    padding: 20px 16px;
15	    height: 480px;
16	    display: flex;
17	    flex-direction: column;
18	}
19	
20	/* Monitor card is a square — matches the square camera inside */
21	.vpatrol-card.monitor-section {
22	    height: auto;
23	    aspect-ratio: 1 / 1;
24	    width: 100%;
25	    max-width: 600px;
26	    margin: 0 auto;
27	}
28	
29	/* =========================================
30	   CONSTRAINED LAYOUT: entire page fits in viewport
31	   vpatrol-main → VPatrol.jsx only
32	   gate-main    → GateScanner.jsx only
33	   ========================================= */
34	.vpatrol-main {
35	    display: flex;
36	    flex-direction: column;
37	    overflow: hidden;           /* stop page-level scroll */
38	    padding: 20px 8px;          /* tighter sides than default dashboard 30px */
39	}
40	
41	.vpatrol-main .vpatrol-grid {
42	    flex: 1;
43	    min-height: 0;              /* allow grid to shrink inside flex parent */
44	    align-items: stretch;       /* both cards fill the row height */
45	}
46	
47	.vpatrol-main .vpatrol-card {
48	    height: 100%;
49	    min-height: 0;
50	    overflow: hidden;
51	}
52	
53	/* camera card: square, capped at 600px, centered in its column */
54	.vpatrol-main .vpatrol-card.monitor-section {
55	    height: auto;
56	    aspect-ratio: 1 / 1;
57	    width: 100%;
58	    max-width: 600px;
59	    margin: 0 auto;
60	}
61	
62	/* timeline: header is fixed, list scrolls internally */
63	.vpatrol-main .vpatrol-list {
64	    flex: 1;
65	    min-height: 0;
66	    overflow-y: auto;
67	}
68	
69	/* GateScanner: mirrors vpatrol-main but single-column, no timeline */
70	.gate-main {
71	    display: flex;
72	    flex-direction: column;
73	    overflow: hidden;
74	    padding: 20px 8px;
75	}
76	
77	.gate-main .vpatrol-grid {
78	    flex: 1;
79	    min-height: 0;
80	    align-items: stretch;
81	}
82	
83	.gate-main .vpatrol-card {
84	    height: 100%;
85	    min-height: 0;
86	    overflow: hidden;
87	}
88	
89	.gate-main .vpatrol-card.monitor-section {
90	    height: auto;
91	    aspect-ratio: 1 / 1;
92	    width: 100%;
93	    max-width: 600px;
94	    margin: 0 auto;
95	}
96	
97	.vpatrol-card h2 {
98	    margin: 0 0 16px 0;
99	    font-size: 1.4rem;
100	    color: #f8fafc;
101	}
102	
103	/* =========================================
104	   2. SURVEILLANCE CCTV FEED DISPLAY
105	   ========================================= */
106	.cctv-container {
107	    position: relative;
108	    width: 100%;
109	    flex: 1;
110	    /* aspect-ratio: 16 / 9; */
111	    background: #0b0f1a;
112	    border-radius: 12px;
113	    overflow: hidden;
114	    border: 2px solid #2d364f;
115	    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
116	}
117	
118	.video-feed {
119	    width: 100%;
120	    height: 100%;
121	    /* object-fit: fill; */
122	    object-fit: cover;
123	    filter: brightness(0.8) contrast(1.25) sepia(5%);
124	}
125	
126	/* Container Border Transitions Based On Scanner States */
127	.state-theme-target_locking { border-color: #06b6d4 !important; box-shadow: 0 0 20px rgba(6, 182, 212, 0.2); }
128	.state-theme-secure_match   { border-color: #10b981 !important; box-shadow: 0 0 25px rgba(16, 185, 129, 0.35); }
129	.state-theme-unknown_query  { border-color: #ef4444 !important; box-shadow: 0 0 25px rgba(239, 68, 68, 0.35); }
130	
131	/* =========================================
132	   3. HIGH-TECH REAL-TIME BOUNDING BOXES
133	   ========================================= */
134	.face-tracking-box {
135	    position: absolute;
136	    border: 1px dashed rgba(255, 255, 255, 0.2);
137	    z-index: 10;
138	    pointer-events: none;
139	    
140	    /* 🎯 COMBINED: Smooth positional gliding + crisp color snapping */
141	    transition: top 0.25s ease-out, 
142	                left 0.25s ease-out, 
143	                width 0.25s ease-out, 
144	                height 0.25s ease-out,
145	                border-color 0.1s linear,
146	                background-color 0.1s linear;
147	}
148	
149	/* Bounding Bracket State Theme Switching Rules */
150	.face-tracking-box.state-target_locking { border-color: #06b6d4; }
151	.face-tracking-box.state-secure_match   { border-color: #10b981; }
152	.face-tracking-box.state-unknown_query  { border-color: #ef4444; animation: shake 0.3s ease; }
153	
154	/* Mechanical Target Edge Brackets layout templates */
155	.corner-bracket {
156	    position: absolute;
157	    width: 14px;
158	    height: 14px;
159	    border: 3px solid #06b6d4;
160	    transition: border-color 0.2s ease;
161	}
162	.state-secure_match .corner-bracket { border-color: #10b981; }
163	.state-unknown_query .corner-bracket { border-color: #ef4444; }
164	
165	.top-left     { top: -2px; left: -2px; border-right: none; border-bottom: none; }
166	.top-right    { top: -2px; right: -2px; border-left: none; border-bottom: none; }
167	.bottom-left  { bottom: -2px; left: -2px; border-right: none; border-top: none; }
168	.bottom-right { bottom: -2px; right: -2px; border-left: none; border-top: none; }
169	
170	/* Cinematic Moving Sci-Fi Target Laser Line */
171	.matrix-scan-line {
172	    position: absolute;
173	    left: 0;
174	    width: 100%;
175	    height: 3px;
176	    background: linear-gradient(to right, transparent, #22d3ee, transparent);
177	    box-shadow: 0 0 12px #22d3ee;
178	    animation: scannerRadarSweep 1.5s ease-in-out infinite alternate;
179	}
180	
181	/* =========================================
182	   4. FLOATING BOX LABELS
183	   ========================================= */
184	.box-identity-panel {
185	    position: absolute;
186	    bottom: -62px;
187	    left: 50%;
188	    transform: translateX(-50%);
189	    display: flex;
190	    flex-direction: column;
191	    align-items: center;
192	    gap: 4px;
193	}
194	
195	.access-status-label {
196	    font-size: 0.65rem;
197	    font-weight: 900;
198	    font-family: monospace;
199	    padding: 3px 8px;
200	    border-radius: 4px;
