import React, { useRef, useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import '../css/Dashboard.css';
import '../css/VPatrol.css'; // Reusing your high-tech tracking box and HUD dashboard styles

const GateScanner = () => {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);

  const [scanStatus, setScanStatus] = useState("SYSTEM_ACTIVE"); 
  const [displayMessage, setDisplayMessage] = useState("PLACE FACE IN VIEWPORT");
  const [faceBox, setFaceBox] = useState(null); 
  const [scanProgress, setScanProgress] = useState(0); 

  const scanStatusRef = useRef("SYSTEM_ACTIVE");
  const lockTimerRef = useRef(null);
  const progressIntervalRef = useRef(null);
  const candidateUserRef = useRef(null); 

  const token = localStorage.getItem("accessToken");
  const ATTENDANCE_SCAN_URL = "http://localhost:5000/api/attendance/scan";

  const changeScanState = (nextState, message) => {
    setScanStatus(nextState);
    scanStatusRef.current = nextState;
    if (message) setDisplayMessage(message);
  };

  useEffect(() => {
    startGateCamera();
    const scanInterval = setInterval(() => performPerimeterScan(), 800); 

    return () => {
      stopGateCamera();
      clearInterval(scanInterval);
      if (lockTimerRef.current) clearTimeout(lockTimerRef.current);
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    };
  }, []);

  const startGateCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: "user" } 
      });
      if (videoRef.current) videoRef.current.srcObject = stream;
      changeScanState("SYSTEM_ACTIVE", "GATE TURNSTILE ONLINE // AWAITING TARGET");
    } catch (err) { 
      changeScanState("HARDWARE_ERR", "HARDWARE FAILURE: CAMERA NOT DETECTED"); 
    }
  };

  const stopGateCamera = () => {
    if (videoRef.current?.srcObject) {
      videoRef.current.srcObject.getTracks().forEach(track => track.stop());
    }
  };

  const processAttendanceTransaction = async (verifiedName) => {
    changeScanState("SECURE_MATCH", "IDENTITY VERIFIED // PROCESSING TIMECARD");
    setScanProgress(100);

    try {
      // 🎯 Hit the Node.js automatic clock-in/out controller
      const res = await axios.post(ATTENDANCE_SCAN_URL, { name: verifiedName }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.data && res.data.action) {
        // Render the exact system response action directly onto the kiosk screen
        const actionMessage = res.data.action.replace(/_/g, " ");
        setDisplayMessage(`🔓 ${verifiedName}: ${actionMessage}`);
      }
    } catch (err) {
      console.error("Attendance Sync Failed:", err);
      setDisplayMessage("🚨 GATE TRANSACTION ROUTING FAULT");
    }

    setTimeout(() => { resetTurnstileKiosk(); }, 4000);
  };

  const performPerimeterScan = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.videoWidth === 0) return;
    if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") return;

    const context = canvas.getContext('2d');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    context.drawImage(video, 0, 0, canvas.width, canvas.height);
    const imageBase64 = canvas.toDataURL('image/jpeg', 0.4);

    try {
      const res = await axios.post('/ai/user/recognize', { image: imageBase64 }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") return;

      if (res.data && res.data.box && res.data.box.length >= 4) {
        let rawX, rawY, boxWidth, boxHeight;
        const [v1, v2, v3, v4] = res.data.box;
        if (v2 > v4 && v3 > v1) { rawY = v1; rawX = v4; boxWidth = v2 - v4; boxHeight = v3 - v1; } 
        else { rawX = v1; rawY = v2; boxWidth = v3; boxHeight = v4; }

        const faceProximityPercentage = (boxWidth / video.videoWidth) * 100; 
        const livenessRatio = res.data.liveness_ratio || 0.5;

        const targetBox = {
          left: `${(rawX / video.videoWidth) * 100}%`, top: `${(rawY / video.videoHeight) * 100}%`,
          width: `${(boxWidth / video.videoWidth) * 100}%`, height: `${(boxHeight / video.videoHeight) * 100}%`
        };

        if (faceProximityPercentage < 8 && scanStatusRef.current !== "LIVENESS_CHECK") {
          changeScanState("PRESENCE_DETECTED", "TARGET DETECTED // MOVE CLOSER");
          setFaceBox(null); 
          return;
        }

        // 🎯 LIVENESS CHECK: Wait for head swing rotation
        if (scanStatusRef.current === "LIVENESS_CHECK") {
          setFaceBox(targetBox);
          if (livenessRatio < 0.35 || livenessRatio > 0.65) {
            await processAttendanceTransaction(candidateUserRef.current);
          }
          return;
        }

        // TARGET LOCKING SEQUENCE
        if (scanStatusRef.current === "SYSTEM_ACTIVE" || scanStatusRef.current === "PRESENCE_DETECTED") {
          changeScanState("TARGET_LOCKING", "LOCKING BIOMETRIC VECTORS...");
          setFaceBox(targetBox);
          setScanProgress(12);

          let progress = 12;
          progressIntervalRef.current = setInterval(() => {
            progress += Math.floor(Math.random() * 14) + 4;
            if (progress >= 96) { setScanProgress(96); clearInterval(progressIntervalRef.current); } 
            else { setScanProgress(progress); }
          }, 120);

          lockTimerRef.current = setTimeout(() => {
            clearInterval(progressIntervalRef.current);

            if (res.data.user && res.data.user.name !== "UNAUTHORIZED") {
              candidateUserRef.current = res.data.user.name;
              changeScanState("LIVENESS_CHECK", "VERIFYING LIVENESS: TURN HEAD SLIGHTLY");
            } else {
              changeScanState("UNKNOWN_QUERY", "🚨 PERIMETER BREACH: ACCESS DENIED");
              setScanProgress(0);
              setTimeout(() => { resetTurnstileKiosk(); }, 3500);
            }
          }, 1800);
        } else if (scanStatusRef.current === "TARGET_LOCKING") {
          setFaceBox(targetBox);
        }
      } else {
        if (scanStatusRef.current !== "LIVENESS_CHECK" && scanStatusRef.current !== "TARGET_LOCKING") {
          resetTurnstileKiosk();
        }
      }
    } catch (err) {
      console.error("Gate AI Link Fault:", err);
    }
  };

  const resetTurnstileKiosk = () => {
    setFaceBox(null);
    setScanProgress(0);
    candidateUserRef.current = null;
    changeScanState("SYSTEM_ACTIVE", "GATE TURNSTILE ONLINE // AWAITING TARGET");
  };

  return (
    <div className="dashboard-layout">
      <Sidebar />
      <main className="dashboard-main gate-main">
        <header className="dashboard-header">
          <div className="header-titles">
            <h1>Perimeter Gate Attendance Terminal</h1>
            <p>Main Facility Entrance Turnstile Facial Recognition Interface</p>
          </div>
        </header>

        <div className="vpatrol-grid" style={{ gridTemplateColumns: '1fr' }}>
          <div className="vpatrol-card monitor-section">
            <div className={`cctv-container state-theme-${scanStatus.toLowerCase()}`} style={{ width: '100%', height: '100%', aspectRatio: '1 / 1', flex: 'none' }}>
              <video ref={videoRef} autoPlay playsInline muted className="video-feed" />
              <canvas ref={canvasRef} style={{ display: 'none' }} />

              {faceBox && (
                <div className={`face-tracking-box state-${scanStatus.toLowerCase()}`} style={{ top: faceBox.top, left: faceBox.left, width: faceBox.width, height: faceBox.height }}>
                  <div className="corner-bracket top-left"></div>
                  <div className="corner-bracket top-right"></div>
                  <div className="corner-bracket bottom-left"></div>
                  <div className="corner-bracket bottom-right"></div>
                  {scanStatus === "TARGET_LOCKING" && <div className="matrix-scan-line"></div>}

                  <div className="box-identity-panel">
                    <span className="access-status-label">
                      {scanStatus === "TARGET_LOCKING" && `ANALYZING: ${scanProgress}%`}
                      {scanStatus === "LIVENESS_CHECK" && "⚠️ ANTI-SPOOF ACTIVE"}
                      {scanStatus === "SECURE_MATCH" && "✓ ACCESS GRANTED"}
                      {scanStatus === "UNKNOWN_QUERY" && "🚨 PERIMETER ALERT"}
                    </span>
                    <span className="person-name-label">{displayMessage}</span>
                  </div>
                </div>
              )}

              <div className="hud-overlay">
                <div className="hud-top">
                  <div className="hud-left-meta">
                    <span className="hud-node">PORTAL_NODE // SOUTH_ENTRANCE_TURNSTILE</span>
                  </div>
                  <span className={`hud-status-badge status-${scanStatus.toLowerCase()}`}>
                    {scanStatus === "SYSTEM_ACTIVE" && "● SYSTEM ARMED"}
                    {scanStatus === "LIVENESS_CHECK" && "🔄 PROCESSING 3D PROFILE"}
                    {scanStatus === "SECURE_MATCH" && "TURNSTILE UNLOCKED"}
                    {scanStatus === "UNKNOWN_QUERY" && "THREAT REJECTED"}
                  </span>
                </div>
                <div className="hud-bottom">
                  <p className="hud-engine-log" style={{ color: '#3b82f6' }}>TERMINAL STATE: {displayMessage}</p>
                </div>
              </div>

            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default GateScanner;

import React, { useRef, useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import '../css/Dashboard.css';
import '../css/VPatrol.css'; 

const VPatrol = () => {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);

  // Staged States: SYSTEM_ACTIVE, PRESENCE_DETECTED, TARGET_LOCKING, LIVENESS_CHECK, SECURE_MATCH, UNKNOWN_QUERY
  const [scanStatus, setScanStatus] = useState("SYSTEM_ACTIVE"); 
  const [identifiedUser, setIdentifiedUser] = useState(null);
  const [faceBox, setFaceBox] = useState(null); 
  const [scanProgress, setScanProgress] = useState(0); 

  const scanStatusRef = useRef("SYSTEM_ACTIVE");
  const lockTimerRef = useRef(null);
  const progressIntervalRef = useRef(null);

  const isScanningRef = useRef(false);

  // LIVENESS MEMORY: Tracks the head-turn validation
  const candidateUserRef = useRef(null); 
  const lastLogRef = useRef({ name: null, timestamp: 0 });

  const [systemTime, setSystemTime] = useState(new Date().toLocaleTimeString('en-SG', { 
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true 
  }));

  const [incidentLogs, setIncidentLogs] = useState([]);

  const token = localStorage.getItem("accessToken");
  const NODE_SERVER_URL = "http://localhost:5000/api/security/logs"; 

  const changeScanState = (nextState) => {
    setScanStatus(nextState);
    scanStatusRef.current = nextState;
  };

  useEffect(() => {
    startCCTV();

    // FETCH PERMANENT LOGS ON LOAD
    axios.get(NODE_SERVER_URL, { headers: { Authorization: `Bearer ${token}` } })
      .then(res => {
        if (res.data && res.data.length > 0) {
          setIncidentLogs(res.data);
        } else {
          setIncidentLogs([{ id: 'SYS-001', time: new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true }), type: 'System Online', desc: 'Biometric sensors initialized.', severity: 'safe', icon: '✅' }]);
        }
      })
      .catch(err => {
        console.error("Database connection waiting...", err);
        setIncidentLogs([{ id: 'SYS-001', time: new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true }), type: 'System Offline', desc: 'Cannot connect to security database.', severity: 'critical', icon: '⚠️' }]);
      });

    const clockInterval = setInterval(() => {
      setSystemTime(new Date().toLocaleTimeString('en-SG', { 
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true 
      }));
    }, 1000);

    const scanInterval = setInterval(() => { 
      performLiveScan(); 
    }, 800); 

    return () => {
      stopCCTV();
      clearInterval(clockInterval);
      clearInterval(scanInterval);
      if (lockTimerRef.current) clearTimeout(lockTimerRef.current);
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    };
  }, []);

  const startCCTV = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: "user" } 
      });
      if (videoRef.current) videoRef.current.srcObject = stream;
      changeScanState("SYSTEM_ACTIVE");
    } catch (err) { 
      changeScanState("HARDWARE_ERR"); 
    }
  };

  const stopCCTV = () => {
    if (videoRef.current?.srcObject) {
      videoRef.current.srcObject.getTracks().forEach(track => track.stop());
    }
  };

  const playFeedback = (type) => {
    const audioPath = type === 'success' ? '/sounds/success.mp3' : '/sounds/denied.mp3';
    const audio = new Audio(audioPath);
    audio.volume = 0.4; 
    audio.play().catch(() => console.log("Audio waiting for user gesture"));
  };

  const grantFinalAccess = (detectedName) => {
    playFeedback('success');
    changeScanState("SECURE_MATCH");
    setIdentifiedUser(detectedName);
    setScanProgress(100);

    const currentTimestamp = Date.now();
    const logTimeStr = new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });

    if (lastLogRef.current.name !== detectedName || (currentTimestamp - lastLogRef.current.timestamp > 30000)) {
      const newLog = {
        id: `ACC-${Math.floor(Math.random() * 900) + 100}`,
        time: logTimeStr,
        type: 'Gantry Access',
        desc: `Identity & Liveness Verified: ${detectedName}`,
        severity: 'safe',
        icon: '🔓',
        personnelName: detectedName 
      };

      setIncidentLogs(prev => [newLog, ...prev.slice(0, 14)]); 
      lastLogRef.current = { name: detectedName, timestamp: currentTimestamp };

      axios.post(NODE_SERVER_URL, newLog, { headers: { Authorization: `Bearer ${token}` } })
        .catch(e => console.log("DB Save Failed", e));
    }

    setTimeout(() => { resetScanner(); }, 3500);
  };

  const performLiveScan = async () => {
    if (isScanningRef.current) return; 

    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.videoWidth === 0) return;
    if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") return;

    isScanningRef.current = true; 

    const context = canvas.getContext('2d');

    // 🚀 LAPTOP OPTIMIZATION: Shrink the image to 480px wide before sending to AI
    // This dramatically reduces the mathematical load on your laptop's weak CPU!
    const MAX_WIDTH = 480; 
    const scaleDownRatio = MAX_WIDTH / video.videoWidth;

    canvas.width = MAX_WIDTH;
    canvas.height = video.videoHeight * scaleDownRatio;

    // Draw the compressed version
    context.drawImage(video, 0, 0, canvas.width, canvas.height);

    // Send a highly compressed JPEG
    const imageBase64 = canvas.toDataURL('image/jpeg', 0.3);

    try {
      const res = await axios.post('/ai/user/recognize', 
        { image: imageBase64 }, 
        { headers: { Authorization: `Bearer ${token}` } }
      );

      if (scanStatusRef.current === "SECURE_MATCH" || scanStatusRef.current === "UNKNOWN_QUERY") {
         isScanningRef.current = false;
         return;
      }

      if (res.data && res.data.box && res.data.box.length >= 4) {

        let rawX, rawY, boxWidth, boxHeight;
        const [v1, v2, v3, v4] = res.data.box;

        // Note: The AI is now returning coordinates based on the SMALL 480px canvas, not the video
        if (v3 > v1 && v4 > v2 && v3 <= canvas.width && v4 <= canvas.height) {
          rawX = v1; rawY = v2; boxWidth = v3 - v1; boxHeight = v4 - v2;
        } else if (v2 > v4 && v3 > v1) {
          rawY = v1; rawX = v4; boxWidth = v2 - v4; boxHeight = v3 - v1; 
        } else {
          rawX = v1; rawY = v2; boxWidth = v3; boxHeight = v4;
        }

        // Calculate proximity based on the compressed canvas width
        const faceProximityPercentage = (boxWidth / canvas.width) * 100; 
        const livenessRatio = res.data.liveness_ratio || 0.5;

        // 🎯 UPDATED MATH: Calculate percentages using the compressed canvas dimensions
        const targetBox = {
          left: `${(rawX / canvas.width) * 100}%`,
          top: `${(rawY / canvas.height) * 100}%`,
          width: `${(boxWidth / canvas.width) * 100}%`,
          height: `${(boxHeight / canvas.height) * 100}%`
        };

        if (faceProximityPercentage < 5 && scanStatusRef.current !== "LIVENESS_CHECK") {
          if (scanStatusRef.current === "SYSTEM_ACTIVE" || scanStatusRef.current === "PRESENCE_DETECTED") {
            changeScanState("PRESENCE_DETECTED");
            setFaceBox(null); 
            setScanProgress(0);
          }
          isScanningRef.current = false; 
          return;
        }

        if (scanStatusRef.current === "LIVENESS_CHECK") {
          setFaceBox(targetBox); 

          if (livenessRatio < 0.45 || livenessRatio > 0.55) {
            grantFinalAccess(candidateUserRef.current);
          }
          return; 
        }

        if (scanStatusRef.current === "SYSTEM_ACTIVE" || scanStatusRef.current === "PRESENCE_DETECTED") {
          changeScanState("TARGET_LOCKING");
          setFaceBox(targetBox);
          setScanProgress(12);

          let progress = 12;
          progressIntervalRef.current = setInterval(() => {
            progress += Math.floor(Math.random() * 14) + 4;
            if (progress >= 96) {
              setScanProgress(96);
              clearInterval(progressIntervalRef.current);
            } else {
              setScanProgress(progress);
            }
          }, 120);

          lockTimerRef.current = setTimeout(() => {
            clearInterval(progressIntervalRef.current);

            const currentTimestamp = Date.now();
            const logTimeStr = new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });

            if (res.data.user && res.data.user.name !== "UNAUTHORIZED") {
              candidateUserRef.current = res.data.user.name;
              changeScanState("LIVENESS_CHECK");
            } else {
              playFeedback('denied');
              changeScanState("UNKNOWN_QUERY");
              setIdentifiedUser("UNKNOWN PERSONNEL");
              setScanProgress(0);

              if (lastLogRef.current.name !== "UNKNOWN" || (currentTimestamp - lastLogRef.current.timestamp > 10000)) {
                const newLog = {
                  id: `SEC-${Math.floor(Math.random() * 900) + 100}`,
                  time: logTimeStr,
                  type: 'Intrusion Alert',
                  desc: 'Unregistered personnel detected at gantry.',
                  severity: 'critical',
                  icon: '🚨',
                  personnelName: null
                };

                setIncidentLogs(prev => [newLog, ...prev.slice(0, 14)]);
                lastLogRef.current = { name: "UNKNOWN", timestamp: currentTimestamp };

                axios.post(NODE_SERVER_URL, newLog, { headers: { Authorization: `Bearer ${token}` } })
                  .catch(e => console.log("DB Save Failed", e));
              }

              setTimeout(() => { resetScanner(); }, 3500);
            }
          }, 1800);

        } else if (scanStatusRef.current === "TARGET_LOCKING") {
          setFaceBox(targetBox);
        }

      } else {
        if (scanStatusRef.current !== "LIVENESS_CHECK" && scanStatusRef.current !== "TARGET_LOCKING") {
          resetScanner();
        }
      }
    } catch (err) {
      console.error("AI Command Loop Fault:", err);
    } finally {
      isScanningRef.current = false; 
    }
  };

  const resetScanner = () => {
    setIdentifiedUser(null);
    setFaceBox(null);
    setScanProgress(0);
    candidateUserRef.current = null;
    changeScanState("SYSTEM_ACTIVE");
  };

  return (
    <div className="dashboard-layout">
      <Sidebar />
      <main className="dashboard-main vpatrol-main">
        <header className="dashboard-header">
          <div className="header-titles">
            <h1>V-Patrol AI Command Center</h1>
            <p>Real-time biometric gantry and anomaly detection timeline</p>
          </div>
        </header>

        <div className="vpatrol-grid">
          <div className="vpatrol-card monitor-section">
            <div className={`cctv-container state-theme-${scanStatus.toLowerCase()}`} style={{ width: '100%', height: '100%', aspectRatio: '1 / 1', flex: 'none' }}>
              <video ref={videoRef} autoPlay playsInline muted className="video-feed" />
              <canvas ref={canvasRef} style={{ display: 'none' }} />

              {faceBox && (
                <div 
                  className={`face-tracking-box state-${scanStatus.toLowerCase()}`}
                  style={{
                    top: faceBox.top,
                    left: faceBox.left,
                    width: faceBox.width,
                    height: faceBox.height
                  }}
                >
                  <div className="corner-bracket top-left"></div>
                  <div className="corner-bracket top-right"></div>
                  <div className="corner-bracket bottom-left"></div>
                  <div className="corner-bracket bottom-right"></div>

                  {scanStatus === "TARGET_LOCKING" && <div className="matrix-scan-line"></div>}

                  <div className="box-identity-panel">
                    <span className="access-status-label">
                      {scanStatus === "TARGET_LOCKING" && `ANALYZING: ${scanProgress}%`}
                      {scanStatus === "LIVENESS_CHECK" && "⚠️ LIVENESS CHECK"}
                      {scanStatus === "SECURE_MATCH" && "✓ GRANT ACCESS"}
                      {scanStatus === "UNKNOWN_QUERY" && "🚨 ACCESS DENIED"}
                    </span>
                    <span className="person-name-label">
                      {scanStatus === "TARGET_LOCKING" && "LOCKING VECTORS..."}
                      {scanStatus === "LIVENESS_CHECK" && "TURN HEAD SLIGHTLY"}
                      {scanStatus === "SECURE_MATCH" && identifiedUser}
                      {scanStatus === "UNKNOWN_QUERY" && "SUSPICIOUS ACTIVITY"}
                    </span>
                  </div>
                </div>
              )}

              <div className="hud-overlay">
                <div className="hud-top">
                  <div className="hud-left-meta">
                    <span className="hud-node">SYS_MODE // BIOMETRIC_GANTRY</span>
                    {scanStatus === "PRESENCE_DETECTED" && (
                      <span className="hud-radar-alert">⚠️ PROXIMITY SIGNAL DETECTED</span>
                    )}
                  </div>
                  <span className={`hud-status-badge status-${scanStatus.toLowerCase()}`}>
                    {scanStatus === "SYSTEM_ACTIVE" && "● IDLE MONITORING"}
                    {scanStatus === "PRESENCE_DETECTED" && "⚡ MOTION ACQUIRED"}
                    {scanStatus === "TARGET_LOCKING" && "⏳ VECTOR LOCK ACTIVE"}
                    {scanStatus === "LIVENESS_CHECK" && "🔄 AWAITING MOVEMENT"}
                    {scanStatus === "SECURE_MATCH" && "SUCCESS MATCH"}
                    {scanStatus === "UNKNOWN_QUERY" && "ALERT WARNING"}
                  </span>
                </div>

                <div className="hud-bottom">
                  <div className="hud-coordinates-telemetry">
                    <p>LAT: 1.3521° N // LON: 103.8198° E</p>
                    <p className="hud-engine-log">MATRIX_ENGINE: ACTIVE_v3.42</p>
                  </div>
                  <p className="hud-clock">{systemTime}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="vpatrol-card timeline-section">
            <div className="section-header">
              <h2>Security Timeline</h2>
            </div>

            <div className="vpatrol-list">
              {incidentLogs.length > 0 ? incidentLogs.map((log) => (
                <div key={log.id} className={`vpatrol-item ${log.severity}`}>
                  <div className="item-header">
                    <span className="item-id">#{log.id}</span>
                    <span className="item-type-timestamp">{log.time}</span>
                  </div>
                  <div className="item-body">
                    <div className="item-icon">{log.icon}</div>
                    <div className="item-text">
                      <h4>{log.type}</h4>
                      <p>{log.desc}</p>
                    </div>
                  </div>
                </div>
              )) : <p>Initializing security sensors...</p>}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default VPatrol;

/* --- Full Screen Takeover --- */
.enrollment-layout {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    background-color: #0f172a; /* Deep FlowGuard background */
    font-family: 'Inter', sans-serif;
    padding: 20px;
}

/* --- The Main Wizard Card --- */
.enrollment-card {
    background-color: #1e293b;
    border: 1px solid #334155;
    border-radius: 20px;
    padding: 40px;
    width: 100%;
    max-width: 600px;
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
    text-align: center;
    animation: slideUpFade 0.5s ease-out;
}

/* --- Header Section --- */
.enrollment-header {
    margin-bottom: 30px;
}

.security-icon {
    font-size: 3rem;
    display: block;
    margin-bottom: 10px;
}

.enrollment-header h2 {
    color: #f8fafc;
    font-size: 1.75rem;
    font-weight: 700;
    margin: 0 0 10px 0;
    letter-spacing: 0.5px;
}

.enrollment-header p {
    color: #94a3b8;
    font-size: 0.95rem;
    line-height: 1.5;
    margin: 0;
}

/* --- Progress Tracker --- */
.progress-tracker {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-bottom: 40px;
    gap: 10px;
}

.tracker-badge {
    background: #334155;
    color: #94a3b8;
    padding: 6px 16px;
    border-radius: 20px;
    font-size: 0.8rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    transition: all 0.3s ease;
}

.tracker-badge.active {
    background: rgba(59, 130, 246, 0.2);
    color: #60a5fa;
    border: 1px solid #3b82f6;
    box-shadow: 0 0 15px rgba(59, 130, 246, 0.3);
}

.tracker-badge.done {
    background: rgba(16, 185, 129, 0.2);
    color: #10b981;
    border: 1px solid #10b981;
}

.tracker-line {
    height: 2px;
    width: 40px;
    background: #334155;
}

/* --- Camera Container & Circular Cutout --- */
.camera-container {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-bottom: 25px;
}

.video-wrapper {
    position: relative;
    width: 100%;
    aspect-ratio: 1 / 1;
    border-radius: 16px;
    overflow: hidden;
    background-color: #000;
    border: 4px solid #334155;
    box-shadow: 0 0 30px rgba(0, 0, 0, 0.5);
    transition: border-color 0.3s ease;
}

.live-video {
    width: 100%;
    height: 100%;
    object-fit: cover; /* Ensures video fills the circle without stretching */
    transform: scaleX(-1); /* MIRRORS the video so it acts like a real mirror */
}

/* --- Face Direction Overlay (The Cool Part) --- */
.face-guide-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    aspect-ratio: 1 / 1;
    border-radius: 16px;
    pointer-events: none;
    box-shadow: inset 0 0 0 0 transparent;
    transition: box-shadow 0.5s ease-in-out;
}

/* Glows specific sides of the circle to guide the user's head */
.face-guide-overlay.front { box-shadow: inset 0 0 20px 5px rgba(59, 130, 246, 0.4); }
.face-guide-overlay.left { box-shadow: inset 40px 0 30px -10px rgba(59, 130, 246, 0.6); }
.face-guide-overlay.right { box-shadow: inset -40px 0 30px -10px rgba(59, 130, 246, 0.6); }

/* --- Preview Grid (Final State) --- */
.preview-grid {
    display: flex;
    justify-content: center;
    gap: 20px;
    animation: fadeIn 0.4s ease-out;
}

.preview-thumb {
    width: 100px;
