.user-bubble {
  align-self: flex-end;
  background-color: #3b82f6;
  color: white;
  border-bottom-right-radius: 2px;
}

/* Input Area */
.chat-input-area {
  padding: 15px;
  background-color: #0f172a;
  display: flex;
  gap: 10px;
}

.chat-input-area input {
  flex: 1;
  background-color: #1e293b;
  border: 1px solid #334155;
  color: white;
  padding: 8px 12px;
  border-radius: 6px;
  outline: none;
}

.chat-input-area button {
  background-color: #3b82f6;
  color: white;
  border: none;
  padding: 8px 15px;
  border-radius: 6px;
  font-weight: 600;
  cursor: pointer;
}

/* Mobile Adjustments */
@media (max-width: 480px) {
  .chat-popup-wrapper {
    right: 10px;
    bottom: 20px;
  }
  .chat-window {
    width: calc(100vw - 20px);
    right: 0;
    height: 60vh;
    max-height: 400px;
  }
}

/* =========================================
   1. SHARED & GLOBAL COMPONENTS
   ========================================= */
.impact-header, 
.features-header, 
.roadmap-header, 
.section-header {
    text-align: center;
    margin-bottom: 50px;
}

.section-title {
    font-size: 2.5rem;
    font-weight: 800;
    color: #f8fafc;
    margin-bottom: 10px;
}

.section-subtitle {
    color: #94a3b8;
    font-size: 1.1rem;
    max-width: 600px;
    margin: 0 auto;
}

/* Merged Pulse Dot Animation */
.pulse-dot {
    width: 12px;
    height: 12px;
    background-color: #10b981;
    border-radius: 50%;
    box-shadow: 0 0 10px #10b981;
    display: inline-block; 
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.5); opacity: 0.5; }
    100% { transform: scale(1); opacity: 1; }
}

/* =========================================
   2. HERO SECTION
   ========================================= */
.hero-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 80px 20px;
    text-align: center;
}

.hero-title {
    font-size: 4rem;
    font-weight: bold;
    margin: 0 0 20px 0;
    background: linear-gradient(to right, #60a5fa, #34d399);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text; 
}

.hero-description {
    font-size: 1.2rem;
    color: #94a3b8;
    max-width: 800px;
    line-height: 1.6;
    margin: 0 0 40px 0;
}

.hero-button {
    background: rgba(37, 99, 235, 0.1); 
    color: #60a5fa;
    border: 1px solid rgba(96, 165, 250, 0.3);
    padding: 12px 30px;
    border-radius: 50px; 
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 10px;
    transition: all 0.3s ease;
    margin-top: 10px;
    text-decoration: none;
}

.hero-button:hover {
    background: rgba(37, 99, 235, 0.2);
    border-color: #60a5fa;
    box-shadow: 0 0 20px rgba(37, 99, 235, 0.15);
}

.hero-button:active {
    transform: translateY(1px);
}

.button-icon {
    transition: transform 0.3s ease;
}

.hero-button:hover .button-icon {
    transform: translateX(4px);
}

/* =========================================
   3. IMPACT STATS (Mission Section)
   ========================================= */
.stats-container {
    padding: 40px 0 5px 0;
}

.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); 
    gap: 30px; 
    max-width: 1200px;
    margin: 40px auto;
    padding: 0 20px;
}

.stat-card {
    padding: 25px;            
    border-radius: 20px; 
    background: linear-gradient(145deg, #1e293b, #0f172a); 
    border: 1px solid #334155;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    transition: transform 0.3s ease, border-color 0.3s ease;
    min-height: 220px;       
}

.stat-card:hover {
    transform: translateY(-10px);
    border-color: #60a5fa;
}

.stat-value {
    font-size: 3rem;
    font-weight: 900;
    color: #60a5fa;
    margin-bottom: 10px;
}

.stat-label {
    font-weight: bold;
    font-size: 1.1rem;
    margin-bottom: 5px;
    color: #f8fafc;
}

.stat-subtext {
    color: #94a3b8;
    font-size: 0.9rem;
}

.status-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    margin-bottom: 8px;
}

.status-text {
    color: #10b981;
    font-weight: 900;
    font-size: 1.1rem;
    letter-spacing: 1px;
}

.more-info-btn {
    margin-top: 20px;
    padding: 8px 20px;
    background: rgba(96, 165, 250, 0.1);
    border: 1px solid rgba(96, 165, 250, 0.3);
    border-radius: 50px;
    color: #60a5fa;
    font-size: 0.8rem;
    font-weight: 800;
    text-transform: uppercase;
    cursor: pointer;
    transition: all 0.3s ease;
}

.more-info-btn:hover {
    background: rgba(96, 165, 250, 0.2);
    border-color: #60a5fa;
}

/* =========================================
   4. LIVE TELEMETRY (Sensor Grid)
   ========================================= */
.live-status-section {
    padding: 60px 20px;
    max-width: 1200px;
    margin: 0 auto;
}

.status-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 30px;
    border-bottom: 1px solid #1e293b;
    padding-bottom: 15px;
}

.status-title {
    color: #f8fafc;
    font-size: 1.5rem;
    margin: 0;
}

.live-indicator {
    display: flex;
    align-items: center;
    gap: 10px;
    color: #10b981;
    font-size: 0.75rem;
    font-weight: 900;
    letter-spacing: 1px;
}

.status-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 20px;
}

.sensor-card {
    background: #0f172a;
    border: 1px solid #1e293b;
    padding: 25px;
    border-radius: 12px;
    position: relative;
    overflow: hidden;
}

.sensor-label {
    display: block;
    color: #64748b;
    font-size: 0.85rem;
    margin-bottom: 10px;
}

.sensor-value {
    color: #f8fafc;
    font-size: 2rem;
    font-weight: 700;
    font-family: monospace;
    margin-bottom: 15px;
}

.sensor-tag {
    font-size: 0.7rem;
    font-weight: bold;
    padding: 4px 10px;
    border-radius: 4px;
    text-transform: uppercase;
}

.sensor-tag.optimal, 
.sensor-tag.active, 
.sensor-tag.stable {
    background: rgba(16, 185, 129, 0.1);
    color: #10b981;
}

.sensor-tag.warning {
    background: rgba(245, 158, 11, 0.1);
    color: #f59e0b;
}

/* =========================================
   5. FEATURES (Industrial Solutions)
   ========================================= */
.features-section {
    padding: 80px 20px 20px 20px;
    max-width: 1200px;
    margin: 0 auto;
}

.features-heading {
    text-align: center;
    margin-bottom: 50px;
    font-size: 2rem;
    color: #f8fafc;
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 30px;
}

.feature-card {
    padding: 40px;
    border-radius: 20px;
    background: linear-gradient(145deg, #1e293b, #0f172a);
    border: 1px solid #334155;
    transition: transform 0.3s ease, border-color 0.3s ease;
}

.feature-card:hover {
    transform: translateY(-10px);
    border-color: #60a5fa;
}

.feature-icon {
    font-size: 2.5rem;
    margin-bottom: 20px;
}

.feature-title {
    font-size: 1.4rem;
    color: #60a5fa;
    margin-bottom: 15px;
}

.feature-description {
    color: #94a3b8;
    line-height: 1.6;
    font-size: 1rem;
}

/* =========================================
   6. TECH STACK (Marquee Slider)
   ========================================= */
.tech-stack-section {
    padding: 40px 0;
    background-color: #0f172a;
    border-top: 1px solid #1e293b;
    border-bottom: 1px solid #1e293b;
    overflow: hidden;
}

.tech-stack-title {
    text-align: center;
    color: #64748b;
    font-size: 0.75rem;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 2px;
    margin-bottom: 25px;
}

.marquee-container {
    display: flex;
    overflow: hidden;
    user-select: none;
    mask-image: linear-gradient(to right, transparent, black 20%, black 80%, transparent);
}

.marquee-content {
    display: flex;
    gap: 60px;
    animation: scrollMarquee 80s linear infinite;
    white-space: nowrap;
}

@keyframes scrollMarquee {
    0% { transform: translateX(0); }
    100% { transform: translateX(-50%); }
}

.marquee-container:hover .marquee-content {
    animation-play-state: paused;
}

.tech-item {
    display: flex;
    align-items: center;
    gap: 12px;
    color: #94a3b8;
    font-size: 1.1rem;
    font-weight: 600;
    font-family: 'Inter', sans-serif;
}

.tech-dot {
    width: 6px;
    height: 6px;
    background-color: #3b82f6;
    border-radius: 50%;
    box-shadow: 0 0 10px #3b82f6;
}

/* =========================================
   7. ROADMAP (Timeline)
   ========================================= */
.roadmap-section {
    padding: 80px 20px 80px 20px;
    max-width: 900px;
    margin: 0 auto;
}

.roadmap-heading {
    text-align: center;
    color: #f8fafc;
    font-size: 2rem;
    margin-bottom: 60px;
}

.timeline-container {
    position: relative;
    border-left: 2px solid #1e293b;
    margin-left: 20px;
    padding-left: 40px;
}

.timeline-item {
    position: relative;
    margin-bottom: 50px;
}

.timeline-item:last-child {
    margin-bottom: 0;
}

.timeline-dot {
    position: absolute;
    left: -51px; 
    top: 5px;
    width: 20px;
    height: 20px;
    background-color: #0f172a;
    border: 3px solid #3b82f6;
    border-radius: 50%;
    box-shadow: 0 0 10px rgba(59, 130, 246, 0.5);
    z-index: 1;
}

.timeline-date {
    display: block;
    color: #60a5fa;
    font-weight: 800;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    margin-bottom: 8px;
}

.timeline-title {
    color: #f8fafc;
    font-size: 1.3rem;
    margin-bottom: 10px;
}

.timeline-desc {
    color: #94a3b8;
    line-height: 1.6;
    font-size: 1rem;
}

/* =========================================
   8. CONTACT FORM
   ========================================= */
.contact-section {
    padding: 80px 20px 20px 20px;
    background: rgba(15, 23, 42, 0.3);
}

.contact-container {
    max-width: 1100px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 1fr 1.5fr;
    gap: 60px;
    background: rgba(30, 41, 59, 0.4);
    padding: 50px;
    border-radius: 24px;
    border: 1px solid #334155;
}

.contact-info h2 {
    font-size: 2.5rem;
    color: #f8fafc;
    margin-bottom: 20px;
}

.contact-form {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.contact-form input, 
.contact-form select, 
.contact-form textarea {
    padding: 15px;
    background: #0f172a;
    border: 1px solid #334155;
    border-radius: 8px;
    color: white;
    font-size: 1rem;
}

.contact-form textarea {
    height: 150px;
    resize: none;
}

.contact-form input:focus {
    border-color: #60a5fa;
    outline: none;
}

/* =========================================
   9. MOBILE OPTIMIZATIONS (Max 768px)
   ========================================= */
@media (max-width: 768px) {
    /* Contact Stack */
    .contact-container {
        grid-template-columns: 1fr;
        padding: 30px;
    }

    /* Roadmap Timeline adjustments */
    .timeline-container {
        margin-left: 10px;
        padding-left: 30px;
    }
    .timeline-dot {
        left: -41px;
    }

    /* Live Status Telemetry fixes */
    .status-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 12px;
        padding-bottom: 20px;
    }

    .status-title {
        font-size: 1.3rem;
    }

    .live-indicator {
        font-size: 0.7rem;
        background: rgba(16, 185, 129, 0.1); 
        padding: 6px 12px;
        border-radius: 20px;
    }

    .status-grid {
        grid-template-columns: 1fr;
        gap: 15px;
    }

    .sensor-card {
        padding: 20px;
    }

    .sensor-value {
        font-size: 1.8rem;
    }
}

@media (max-width: 480px) {
    .hero-title {
        font-size: clamp(1.8rem, 5vw, 2.5rem);
    }
    .hero-description {
        font-size: 0.95rem;
        line-height: 1.5;
    }
    .section-title {
        font-size: 1.8rem;
    }
    .hero-container {
        padding: 50px 16px;
    }
}

